                <option value="Classifier Tuning" ${reqItem.requestType === 'Classifier Tuning' ? 'selected' : ''}>Classifier Tuning</option>
                <option value="Escalation Exemption" ${reqItem.requestType === 'Escalation Exemption' ? 'selected' : ''}>Escalation Exemption</option>
                <option value="DSA Export" ${reqItem.requestType === 'DSA Export' ? 'selected' : ''}>DSA Export</option>
