  async function handleFormSubmit(event) {
    event.preventDefault();

    const idVal = document.getElementById("form-request-id").value;
    const clientVal = document.getElementById("form-client").value.trim();
    const titleVal = document.getElementById("form-title").value.trim();
    const typeVal = document.getElementById("form-type").value;
    const priorityVal = document.getElementById("form-priority").value;
    const statusVal = document.getElementById("form-status").value;
    const ownerEmailVal = document.getElementById("form-owner").value;
    const dateVal = document.getElementById("form-date").value;
    const descriptionVal = document.getElementById("form-description").value.trim();
    const notesVal = document.getElementById("form-notes").value.trim();

    if (selectedRequestId === "NEW") {
      let maxNum = 200;
      requests.forEach(r => {
        const match = r.id.match(/^REQ-(\d+)$/);
        if (match) {
          const num = parseInt(match[1]);
          if (num > maxNum) maxNum = num;
        }
      });
      const nextId = `REQ-${maxNum + 1}`;

      const newReq = {
        id: nextId,
        client: clientVal,
        requestTitle: titleVal,
        requestType: typeVal,
        priority: priorityVal,
        status: statusVal,
        assignedLead: ownerEmailVal,
        dateSubmitted: dateVal,
        description: descriptionVal,
        deliverableNotes: notesVal
      };

      requests.push(newReq);
      selectedRequestId = nextId;
    } else {
      const idx = requests.findIndex(r => r.id === idVal);
      if (idx !== -1) {
        requests[idx].client = clientVal;
        requests[idx].requestTitle = titleVal;
        requests[idx].requestType = typeVal;
        requests[idx].priority = priorityVal;
        requests[idx].status = statusVal;
        requests[idx].assignedLead = ownerEmailVal;
        requests[idx].dateSubmitted = dateVal;
        requests[idx].description = descriptionVal;
        requests[idx].deliverableNotes = notesVal;
      }
    }

    await saveState();
    renderRequestsList();
    renderDetailsPane();
  }

  async function deleteRequest(id) {
    if (!confirm(`Are you sure you want to delete client request ${id}?`)) {
      return;
    }

    requests = requests.filter(r => r.id !== id);
    selectedRequestId = null;

    await saveState();
    renderRequestsList();
    renderDetailsPane();
  }

  async function init() {
    await loadState();
    if (envId) {
      setInterval(loadState, 2000);
    }
  }

  window.addEventListener('DOMContentLoaded', init);
</script>
</body>
